/* ── Language engine ─────────────────────────────────────── */
function bmApplyLang(lang) {
  const dict = I18N[lang];
  if (!dict) return;

  document.documentElement.lang = lang;

  // Page title
  const titleKey = document.body.dataset.i18nTitle;
  if (titleKey && dict[titleKey]) document.title = dict[titleKey];

  // innerHTML replacements (complex HTML with tags)
  document.querySelectorAll('[data-i18n-html]').forEach(el => {
    const v = dict[el.dataset.i18nHtml];
    if (v !== undefined) el.innerHTML = v;
  });

  // textContent replacements — smart: if element has child elements, update last text node only
  document.querySelectorAll('[data-i18n]').forEach(el => {
    const v = dict[el.dataset.i18n];
    if (v === undefined) return;
    if (el.children.length === 0) {
      el.textContent = v;
    } else {
      const nodes = [...el.childNodes];
      for (let i = nodes.length - 1; i >= 0; i--) {
        if (nodes[i].nodeType === Node.TEXT_NODE && nodes[i].textContent.trim()) {
          nodes[i].textContent = ' ' + v;
          return;
        }
      }
    }
  });

  // Placeholder replacements
  document.querySelectorAll('[data-i18n-placeholder]').forEach(el => {
    const v = dict[el.dataset.i18nPlaceholder];
    if (v !== undefined) el.placeholder = v;
  });

  localStorage.setItem('bm_lang', lang);
}

function bmInitLang() {
  const saved = localStorage.getItem('bm_lang') || 'fr';
  document.querySelectorAll('.lang-btn').forEach(btn => {
    btn.classList.toggle('active', btn.dataset.lang === saved);
    btn.addEventListener('click', () => {
      document.querySelectorAll('.lang-btn').forEach(b => b.classList.remove('active'));
      btn.classList.add('active');
      bmApplyLang(btn.dataset.lang);
    });
  });
  if (saved !== 'fr') bmApplyLang(saved);
}
